import{_ as t,o as i,c as s,ak as e}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"一份优秀简历的标准","description":"","frontmatter":{},"headers":[],"relativePath":"interview/resume/standard.md","filePath":"interview/resume/standard.md","lastUpdated":1774284433000}'),r={name:"interview/resume/standard.md"};function n(l,a,d,h,o,p){return i(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="一份优秀简历的标准" tabindex="-1">一份优秀简历的标准 <a class="header-anchor" href="#一份优秀简历的标准" aria-label="Permalink to “一份优秀简历的标准”">​</a></h1><blockquote><p>简历是你递给面试官的第一张名片，它决定了面试官是否愿意花时间了解你。</p></blockquote><h2 id="为什么简历如此重要" tabindex="-1">为什么简历如此重要 <a class="header-anchor" href="#为什么简历如此重要" aria-label="Permalink to “为什么简历如此重要”">​</a></h2><p>在春招和秋招的旺季，HR 每天可能收到数百份简历。一份简历的平均阅读时间只有 <strong>6~7 秒</strong>——如果这 7 秒内无法让 HR 看到价值点，你的简历就会被直接 pass。</p><p>简历的核心目标只有一个：<strong>让面试官产生「想见这个人」的兴趣</strong>。</p><h2 id="好简历的五个标准" tabindex="-1">好简历的五个标准 <a class="header-anchor" href="#好简历的五个标准" aria-label="Permalink to “好简历的五个标准”">​</a></h2><h3 id="_1-目标明确" tabindex="-1">1. 目标明确 <a class="header-anchor" href="#_1-目标明确" aria-label="Permalink to “1. 目标明确”">​</a></h3><p>不要试图用一份简历投所有公司。简历应该有清晰的求职方向（后端 / 客户端 / 算法 / 全栈），让人一眼就知道你擅长什么。</p><p>反面示范：</p><blockquote><p>熟练掌握 Java、Python、Go、C++，熟悉前端框架 Vue/React...</p></blockquote><p>正面示范：</p><blockquote><p>后端开发工程师，专注 Java / Spring Cloud 技术栈，主攻分布式系统与高并发场景。</p></blockquote><h3 id="_2-技术栈清晰" tabindex="-1">2. 技术栈清晰 <a class="header-anchor" href="#_2-技术栈清晰" aria-label="Permalink to “2. 技术栈清晰”">​</a></h3><p>技术栈是简历的核心，必须做到：</p><ul><li><strong>分类清晰</strong>：基础、框架、中间件、工具</li><li><strong>用词准确</strong>：写「掌握」而不写「精通」，除非你真的精通</li><li><strong>突出差异化</strong>：不要只列学过的课，要写解决了什么问题</li></ul><div class="language-markdown line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**语言**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">：Java（JDK 17）、Python、SQL</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**框架**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">：Spring Boot、Spring Cloud、Dubbo、MyBatis-Plus</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**中间件**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">：Redis、RocketMQ、Kafka、Nacos、Sentinel</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**工具**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">：Git、Docker、K8s、Jenkins、Arthas</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_3-项目经历有亮点" tabindex="-1">3. 项目经历有亮点 <a class="header-anchor" href="#_3-项目经历有亮点" aria-label="Permalink to “3. 项目经历有亮点”">​</a></h3><p>项目经历是简历的重中之重。好项目的三个特征：</p><table tabindex="0"><thead><tr><th>特征</th><th>说明</th></tr></thead><tbody><tr><td><strong>规模感</strong></td><td>数据量、用户量、QPS 能说明系统的量级</td></tr><tr><td><strong>挑战性</strong></td><td>遇到了什么问题，如何解决的</td></tr><tr><td><strong>可量化</strong></td><td>性能提升了多少，延迟降低了几倍</td></tr></tbody></table><h3 id="_4-结构合理篇幅适中" tabindex="-1">4. 结构合理篇幅适中 <a class="header-anchor" href="#_4-结构合理篇幅适中" aria-label="Permalink to “4. 结构合理篇幅适中”">​</a></h3><ul><li><strong>一页纸原则</strong>：应届生和工作 3 年以内，一页就够</li><li><strong>模块顺序</strong>：个人信息 → 技术栈 → 教育背景 → 项目经历 → 其他</li><li><strong>留白适当</strong>：不要密密麻麻，字号不小于 10.5pt</li></ul><h3 id="_5-无错别字与格式统一" tabindex="-1">5. 无错别字与格式统一 <a class="header-anchor" href="#_5-无错别字与格式统一" aria-label="Permalink to “5. 无错别字与格式统一”">​</a></h3><p>格式问题看似小事，实则暴露态度：</p><ul><li>英文名大小写统一（JavaScript 而非 javascript）</li><li>技术栈版本号注明（JDK 17 而非 Java）</li><li>日期格式一致（2023.06 - 2023.09）</li></ul><h2 id="常见简历问题" tabindex="-1">常见简历问题 <a class="header-anchor" href="#常见简历问题" aria-label="Permalink to “常见简历问题”">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>后果</th><th>解决方案</th></tr></thead><tbody><tr><td>写太多无关内容</td><td>重点被稀释</td><td>按岗位 JD 删减，突出匹配度</td></tr><tr><td>项目描述太模糊</td><td>无法判断能力</td><td>用数据量化，用 STAR 法则描述</td></tr><tr><td>技能全写「精通」</td><td>显得不真诚</td><td>按实际掌握程度分层：熟悉 / 掌握 / 精通</td></tr><tr><td>使用花哨模板</td><td>HR 工具解析困难</td><td>保持简洁，优先 ATS 友好格式</td></tr></tbody></table><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>简历的核心公式：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>好简历 = 清晰的定位 + 扎实的技术栈 + 有数据支撑的项目经历 + 无死角的格式</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>打磨简历是一个反复迭代的过程，每投递一次都是一次反馈机会。简历投出去之前，找一个有经验的人帮你 review 一遍，往往能发现很多自己看不到的问题。</p>`,30)])])}const c=t(r,[["render",n]]);export{b as __pageData,c as default};
